using Microsoft.JSInterop;
using Interop = Microsoft.AspNetCore.Components.Web.BrowserNavigationManagerInterop;

namespace Microsoft.AspNetCore.Components.Server.Circuits;

internal sealed class RemoteNavigationInterception : INavigationInterception
{
    private IJSRuntime _jsRuntime;

    public void AttachJSRuntime(IJSRuntime jsRuntime)
    {
        if (HasAttachedJSRuntime)
        {
            throw new InvalidOperationException("JSRuntime has already been initialized.");
        }

        _jsRuntime = jsRuntime;
    }

    public bool HasAttachedJSRuntime => _jsRuntime != null;

    public async Task EnableNavigationInterceptionAsync()
    {
        if (!HasAttachedJSRuntime)
        {
            // We should generally never get here in the ordinary case. Router will only call this API once pre-rendering is complete.
            // This would guard any unusual usage of this API.
            throw new InvalidOperationException("Navigation commands can not be issued at this time. This is because the component is being " +
                "prerendered and the page has not yet loaded in the browser or because the circuit is currently disconnected. " +
                "Components must wrap any navigation calls in conditional logic to ensure those navigation calls are not " +
                "attempted during prerendering or while the client is disconnected.");
        }

        await _jsRuntime.InvokeAsync<object>(Interop.EnableNavigationInterception, WebRendererId.Server);
    }
}

using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc.Routing;
using Microsoft.AspNetCore.Routing;
using Microsoft.Extensions.Options;
using OrchardCore.ContentManagement.Routing;

namespace OrchardCore.Autoroute.Routing;

public class AutorouteTransformer : DynamicRouteValueTransformer
{
    private readonly IAutorouteEntries _entries;
    private readonly AutorouteOptions _options;

    public AutorouteTransformer(IAutorouteEntries entries, IOptions<AutorouteOptions> options)
    {
        _entries = entries;
        _options = options.Value;
    }

    public override async ValueTask<RouteValueDictionary> TransformAsync(HttpContext httpContext, RouteValueDictionary values)
    {
        (var found, var entry) = await _entries.TryGetEntryByPathAsync(httpContext.Request.Path.Value);

        if (found)
        {
            var routeValues = new RouteValueDictionary(_options.GlobalRouteValues)
            {
                [_options.ContentItemIdKey] = entry.ContentItemId,
            };

            if (!string.IsNullOrEmpty(entry.JsonPath))
            {
                routeValues[_options.JsonPathKey] = entry.JsonPath;
            }

            // Prevents the original values from being re-added to the dynamic ones.
            values.Clear();

            return routeValues;

        }

        return null;
    }
}

using Ardalis.SharedKernel;
using Clean.Architecture.Core.ContributorAggregate;
using Clean.Architecture.Infrastructure;
using Clean.Architecture.UseCases.Contributors.Create;

namespace Clean.Architecture.Web.Configurations;

public static class MediatorConfig
{
  // Should be called from ServiceConfigs.cs, not Program.cs
  public static IServiceCollection AddMediatorSourceGen(this IServiceCollection services,
    Microsoft.Extensions.Logging.ILogger logger)
  {
    logger.LogInformation("Registering Mediator SourceGen and Behaviors");
    services.AddMediator(options =>
    {
      // Lifetime: Singleton is fastest per docs; Scoped/Transient also supported.
      options.ServiceLifetime = ServiceLifetime.Scoped;

      // Supply any TYPE from each assembly you want scanned (the generator finds the assembly from the type)
      options.Assemblies =
      [
        typeof(Contributor),                       // Core
        typeof(CreateContributorCommand),         // UseCases
        typeof(InfrastructureServiceExtensions), // Infrastructure
        typeof(MediatorConfig)                  // Web
      ];

      // Register pipeline behaviors here (order matters)
      options.PipelineBehaviors =
      [
        typeof(LoggingBehavior<,>)
      ];

      // If you have stream behaviors:
      // options.StreamPipelineBehaviors = [ typeof(YourStreamBehavior<,>) ];
    });

    // Alternative: register behaviors via DI yourself (useful if not doing AOT):
    // services.AddScoped(typeof(IPipelineBehavior<,>), typeof(LoggingBehavior<,>));
    // services.AddScoped(typeof(IPipelineBehavior<,>), typeof(CachingBehavior<,>));

    return services;
  }
}
